77	// findArtifactByID locates an artifact across the resolver's projects by ID.
78	// Falls back to scanning the resolver working directory when no project state
79	// is configured. Returns (nil, nil) when no artifact matches.
80	func findArtifactByID(r *Resolver, id string) (*Artifact, error) {
81		roots := []string{}
82		if r.State != nil {
83			for _, p := range r.State.GetProjectSnapshots(false) {
84				if p.Path != "" {
85					roots = append(roots, p.Path)
86				}
87			}
88		}
89		if len(roots) == 0 && r.WorkingDir != "" {
90			roots = append(roots, r.WorkingDir)
91		}
92		for _, root := range roots {
93			artifacts, err := collectArtifacts(root)
94			if err != nil {
95				continue
96			}
97			for _, a := range artifacts {
98				if a.ID == id {
99					return a, nil
100				}
101			}
102		}
103		return nil, nil
104	}
